mapper.select:
SELECT P.PLR_ID, P.PLR_NM, P.PLR_ENG_NM, P.PLR_HGT, P.PLR_WGT, P.PLR_BAT_PTCH_HAND_CD, P.PLR_ANSL_SAL, P.PLR_NTNLT, P.PLR_FRGN_YN, P.PLR_STTS_CD, P.PLR_OVRL_ABLT, P.PLR_POT_ABLT, T.TM_ID, T.TM_KR_NM, T.TM_SHRT_KR_NM, PC.REPR_POSN_CD, RC.CD_NM AS REPR_POSN_NM FROM PLR P LEFT JOIN TM T ON T.TM_ID = P.TM_ID LEFT JOIN ( SELECT PLR_ID, REPR_POSN_CD FROM PLR_TM_CNTRCT WHERE FA_CNTRCT_END_DT >= CURDATE() OR FA_CNTRCT_END_DT IS NULL GROUP BY PLR_ID ) PC ON PC.PLR_ID = P.PLR_ID LEFT JOIN CMN_CD RC ON RC.CD_ID = 'REPR_POSN' AND RC.CD_VAL = PC.REPR_POSN_CD
AND P.TM_ID = #{tmId} AND P.PLR_STTS_CD = #{plrSttsCd}
ORDER BY P.TM_ID, P.PLR_ID

SELECT PLR_ID, SSNT_YR, FATG, COND
FROM PLR_FATG_COND
WHERE PLR_ID  = #{plrId}
  AND SSNT_YR = #{ssntYr}

mapper.update:
UPDATE PLR_ABLT
   SET ABLT_VAL = #{abltVal}
 WHERE PLR_ID  = #{plrId}
   AND ABLT_CD = #{abltCd}

UPDATE PLR_POSN
   SET POSN_PRFC_ABLT = #{posnPrfcAblt}
 WHERE PLR_ID  = #{plrId}
   AND POSN_CD = #{posnCd}

UPDATE PLR
   SET PLR_POT_ABLT = #{potAblt}
 WHERE PLR_ID = #{plrId}

UPDATE PLR
   SET PLR_OVRL_ABLT = (
       SELECT ROUND(AVG(A.ABLT_VAL))
         FROM PLR_ABLT A
        WHERE A.PLR_ID = #{plrId}
   )
 WHERE PLR_ID = #{plrId}
